-- COMPLIANCE CALENDAR — recurring annual and monthly items
SELECT '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID, id,
  'Annual Review: ' || title,
  'Annual compliance review required for: ' || title,
  (DATE_TRUNC('year', NOW()) + INTERVAL '1 year' - INTERVAL '1 day')::DATE,
  'annual', 'upcoming', 30
FROM compliance_rules
WHERE agency_id = '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID
  AND rule_code IN ('AA05-005','LIC-001','LIC-002','PRIV-004');

SELECT '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID, id,
  'Annual Social Media Compliance Audit',
  'Complete annual review of all social media profiles. Verify compliance. Apply all 26 checklist items to active posts.',
  (DATE_TRUNC('year', NOW()) + INTERVAL '11 months')::DATE,
  'annual', 'upcoming', 14
FROM compliance_rules WHERE agency_id = '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID AND rule_code = 'SM-001' LIMIT 1;

SELECT '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID, id,
  'Annual Customer Privacy Notice Distribution',
  'Send annual GLBA privacy notice to all active customers using SF-approved language.',
  (DATE_TRUNC('year', NOW()) + INTERVAL '11 months')::DATE,
  'annual', 'upcoming', 30
FROM compliance_rules WHERE agency_id = '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID AND rule_code = 'PRIV-003';

SELECT '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID, id,
  'W-2 and 1099-NEC Filing Deadline — January 31',
  'Issue all W-2s and 1099-NECs to recipients. File copies with SSA/IRS.',
  (DATE_TRUNC('year', NOW()) + INTERVAL '1 year' + INTERVAL '30 days')::DATE,
  'annual', 'upcoming', 30
FROM compliance_rules WHERE agency_id = '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID AND rule_code = 'LIC-001' LIMIT 1;

SELECT '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID, id,
  'E&O Insurance Renewal — Begin Process',
  'Begin E&O insurance renewal process. Confirm coverage amounts meet current SF minimums.',
  (NOW() + INTERVAL '9 months')::DATE,
  'annual', 'upcoming', 90
FROM compliance_rules WHERE agency_id = '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID AND rule_code = 'LIC-003';

SELECT '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID, id,
  'Monthly Auto Application Compliance Review',
  'Pull RAZ000BT report. Review all required auto application metrics. Review SAM report (RAZ000BV).',
  (DATE_TRUNC('month', NOW()) + INTERVAL '1 month' - INTERVAL '1 day')::DATE,
  'monthly', 'upcoming', 7
FROM compliance_rules WHERE agency_id = '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID AND rule_code = 'LIC-005';

SELECT '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID, id,
  'Monthly Altered Monies History Review',
  'Review and document history of Altered Monies for the month.',
  (DATE_TRUNC('month', NOW()) + INTERVAL '1 month' - INTERVAL '1 day')::DATE,
  'monthly', 'upcoming', 3
FROM compliance_rules WHERE agency_id = '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID AND rule_code = 'FIN-007';

SELECT '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID, id,
  'Monthly PFA Bank Statement Reconciliation',
  'Reconcile Premium Fund Account bank statement. Maintain 3 months of reconciled PFA statements.',
  (DATE_TRUNC('month', NOW()) + INTERVAL '1 month' + INTERVAL '14 days')::DATE,
  'monthly', 'upcoming', 3
FROM compliance_rules WHERE agency_id = '0b8a0268-6b30-4e77-a40a-bc8ee77b5a6c'::UUID AND rule_code = 'FIN-001';;
